const content = $input.first().json.choices?.[0]?.message?.content || '';
let json;
try {
  json = JSON.parse(content);
} catch (e) {
  json = { query: 'cafe restaurant', radius: 1500 };
}
if (!json.query) json.query = 'cafe restaurant';
if (!json.radius) json.radius = 1500;
return [{ json: { searchParams: json, context: $('Fetch Context').item.json.context } }];

const fsqResponse = $input.first().json;
const results = Array.isArray(fsqResponse.results) ? fsqResponse.results : [];
const context = $('Parse Search Params').item.json.context;

if (results.length === 0) {
  return [{ json: { context, places: [], zeroResults: true } }];
}

const places = results.slice(0, 20).map(r => {
  const loc = r.location || {};
  const geocodes = r.geocodes || {};
  const main = geocodes.main || {};
  const address = loc.formatted_address || [loc.address, loc.locality, loc.region].filter(Boolean).join(', ');
  return {
    place_id: r.fsq_place_id || '',
    name: r.name || 'Unnamed',
    address: address,
    description: '',
    types: (r.categories || []).map(c => c.name).filter(Boolean),
    distance_meters: 0,
    lat: main.latitude || null,
    lng: main.longitude || null,
  };
});

return [{ json: { context, places, zeroResults: false } }];

